import sys

def read_numbers():
    line = sys.stdin.readline().strip()
    if not line:
        return []
    return list(map(int, line.split()))

def build_prefix(values):
    prefix = [0]
    total = 0
    for value in values:
        total += value
        prefix.append(total)
    return prefix

def clamp_pair(left, right, n):
    if left < 1:
        left = 1
    if right > n:
        right = n
    return left, right

def range_sum(prefix, left, right):
    left, right = clamp_pair(left, right, len(prefix) - 1)
    return prefix[right] - prefix[left - 1]

