def update_run(ch, cur, best):
    if ch == '1':
        cur += 1
        if cur > best:
            best = cur
    else:
        cur = 0
    return cur, best

def solve_case(text, cur, best):
    for ch in text.strip():
        cur, best = update_run(ch, cur, best)
    return cur, best

def normalize(text):
    return ''.join(ch for ch in text if ch in '01')

