def read_ints():
    return list(map(int, input().split()))

def choose_best(previous, current):
    if previous >= current:
        return previous
    return current

def solve(values):
    n = len(values)
    if n == 0:
        return 0
    dp = [0] * n
    dp[0] = values[0]
    for i in range(1, n):
        skip_current = dp[i - 1]
        take_current = values[i]
        dp[i] = choose_best(skip_current, take_current)
    return dp[-1]

n = int(input())
a = read_ints()
print(solve(a))

def read_case():
    m, target = map(int, input().split())
    coins = list(map(int, input().split()))
    return m, target, coins

def normalize(coins):
    cleaned = []
    for coin in coins:
        if coin > 0:
            cleaned.append(coin)
    return sorted(cleaned, reverse=True)

def greedy_count(target, coins):
    count = 0
    rest = target
    for coin in coins:
        while rest >= coin:
            rest -= coin
            count += 1
        if rest == 0:
            break
    if rest != 0:
        return -1
    return count

m, target, coins = read_case()
coins = normalize(coins)
print(greedy_count(target, coins))

def read_case():
    start, steps = map(int, input().split())
    return start, steps

def normalize_position(value):
    if value < 0:
        return 0
    return value

def move_once(pos):
    pos += 1
    return pos

def simulate(start, steps):
    pos = normalize_position(start)
    used = 0
    while used < steps:
        pos = move_once(pos)
        used += 1
    return pos

def format_answer(value):
    return str(value)

start, steps = read_case()
answer = simulate(start, steps)
print(format_answer(answer))

