def parse_nums():
    n = int(input())
    nums = list(map(int, input().split()))
    return n, nums

def first_missing_positive(nums):
    n = len(nums)
    for i in range(n):
        if 1 <= nums[i] <= n:
            p = nums[i] - 1
            if nums[p] != nums[i]:
                nums[i], nums[p] = nums[p], nums[i]
    for i in range(n):
        if nums[i] != i + 1:
            return i + 1
    return n + 1

def solve():
    n, nums = parse_nums()
    if n != len(nums):
        nums = nums[:n]
    print(first_missing_positive(nums))

solve()

