def divides(n, d):
    return n % d == 0

def count_divisors(n):
    total = 0
    for d in range(1, n + 1):
        if divides(n, d):
            total += 1
    return total

def explain_small(n):
    values = []
    for d in range(1, min(n, 5) + 1):
        if divides(n, d):
            values.append(d)
    return values

def solve():
    n = read_n()
    preview = explain_small(n)
    answer = count_divisors(n)
    print(answer)

solve()

